const single = (id, category, prompt, choices, answer, explanation) => ({
  id,
  type: "single",
  category,
  prompt,
  choices,
  answers: [answer],
  explanation,
});

const multiple = (id, category, prompt, choices, answers, explanation) => ({
  id,
  type: "multiple",
  category,
  prompt,
  choices,
  answers,
  explanation,
});

const matching = (id, category, prompt, pairs, options, explanation) => ({
  id,
  type: "matching",
  category,
  prompt,
  pairs: pairs.map(([term, description]) => ({ term, description })),
  options,
  explanation,
});

